typedef struct ThreadedNode {
    int data;
    struct ThreadedNode *left;
    struct ThreadedNode *right;
    int ltag;  // 0 = thread (predecessor), 1 = child
    int rtag;  // 0 = thread (successor), 1 = child
} ThreadedNode;

def inorder_threaded(root):
    # Find leftmost node to start
    current = root
    while current.left and current.ltag == 1:
        current = current.left

    # Traverse using threads
    while current is not None:
        print(current.data, end=' ')  # Visit node

        if current.rtag == 0:
            # Right is a thread - follow it to successor
            current = current.right
        else:
            # Right is a child - go to right child,
            # then to its leftmost descendant
            current = current.right
            while current and current.ltag == 1:
                current = current.left

# Example usage would require a pre-threaded tree
